-- ===========================================
-- SEED: LsGesso - ~1000 registros total
-- ===========================================

-- =====================
-- 1. EMPLOYEES (50)
-- =====================

-- =====================
-- 2. ADMIN_ACCESS (6 admins)
-- =====================

-- =====================
-- 3. PRODUCTS (30 produtos de gesso)
-- =====================

-- =====================
-- 4. COMPLETE_ORDERS (200)
-- =====================

-- =====================
-- 5. ORDERS (400 - 2 por complete_order)
-- =====================
DO $$
DECLARE
    co_rec RECORD;
    room_names TEXT[] := ARRAY['Sala de Estar','Quarto Principal','Quarto Secundário','Cozinha','Banheiro Social','Banheiro Suíte','Corredor','Hall de Entrada','Varanda','Escritório','Sala de Jantar','Lavabo','Área de Serviço','Closet','Home Theater','Garagem','Sacada','Copa','Despensa','Área Gourmet'];
    r1_idx INT;
    r2_idx INT;
    area1 DECIMAL;
    area2 DECIMAL;
    amount1 DECIMAL;
    amount2 DECIMAL;
BEGIN
    FOR co_rec IN SELECT id, gross_amount, created_at FROM complete_order ORDER BY id LOOP
        r1_idx := ((co_rec.id - 1) % 20) + 1;
        r2_idx := ((co_rec.id + 9) % 20) + 1;
        area1 := 8.0 + (co_rec.id % 30);
        area2 := 6.0 + ((co_rec.id + 5) % 25);
        amount1 := ROUND((co_rec.gross_amount * 0.6)::numeric, 2);
        amount2 := ROUND((co_rec.gross_amount * 0.4)::numeric, 2);

    END LOOP;
END $$;

-- =====================
-- 6. ORDER_PRODUCTS (~800 - 2 produtos por order)
-- =====================
DO $$
DECLARE
    ord_rec RECORD;
    prod_count INT;
    p1_id INT;
    p2_id INT;
    qty1 INT;
    qty2 INT;
BEGIN
    SELECT COUNT(*) INTO prod_count FROM product;

    FOR ord_rec IN SELECT id, gross_amount FROM "order" ORDER BY id LOOP
        p1_id := ((ord_rec.id - 1) % prod_count) + 1;
        p2_id := ((ord_rec.id + 14) % prod_count) + 1;
        IF p2_id = p1_id THEN
            p2_id := (p2_id % prod_count) + 1;
        END IF;

        qty1 := GREATEST(1, (ord_rec.id % 10) + 1);
        qty2 := GREATEST(1, ((ord_rec.id + 3) % 8) + 1);

    END LOOP;
END $$;

